#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-06-11

# test-server-json.sh — MCP registry manifest invariants.
#
# server.json is published to registry.modelcontextprotocol.io on every tag
# by .github/workflows/release.yml (publish-mcp-registry). These checks move
# the publish-time contract left to pre-merge:
#
#   1. .version matches version.txt (release-please bumps both; a mismatch
#      means the extra-files jsonpath silently no-opped — release-please
#      warns-and-proceeds on unmatched paths, it never fails the PR).
#   2. packages[0] uses the CANONICAL OCI shape the live registry validator
#      enforces: tag-less identifier in-repo (the workflow stamps ":$TAG" at
#      publish), and NO registryBaseUrl / version fields ("old format",
#      hard-rejected by ValidateOCI).
#   3. The Dockerfile ownership label matches .name — the registry pulls the
#      image and checks io.modelcontextprotocol.server.name at publish time.

set -euo pipefail

REPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"
SERVER_JSON="$REPO_ROOT/server.json"
FAILURES=0

fail() {
  echo "FAIL: $1"
  FAILURES=$((FAILURES + 1))
}

pass() {
  echo "  OK: $1"
}

echo "server.json invariants:"

# --- 1. version coherence -----------------------------------------------
VERSION_TXT="$(cat "$REPO_ROOT/version.txt")"
SERVER_VERSION="$(jq -r '.version' "$SERVER_JSON")"
if [ "$SERVER_VERSION" = "$VERSION_TXT" ]; then
  pass "version ($SERVER_VERSION) matches version.txt"
else
  fail "version ($SERVER_VERSION) != version.txt ($VERSION_TXT) — release-please extra-files jsonpath no-opped?"
fi

# --- 2. canonical OCI package shape --------------------------------------
if jq -e 'has("packages") and (.packages | length > 0)' "$SERVER_JSON" >/dev/null; then
  REGISTRY_TYPE="$(jq -r '.packages[0].registryType' "$SERVER_JSON")"
  IDENTIFIER="$(jq -r '.packages[0].identifier' "$SERVER_JSON")"
  TRANSPORT="$(jq -r '.packages[0].transport.type' "$SERVER_JSON")"

  [ "$REGISTRY_TYPE" = "oci" ] \
    && pass "packages[0].registryType is oci" \
    || fail "packages[0].registryType is '$REGISTRY_TYPE', expected oci"

  [ "$TRANSPORT" = "stdio" ] \
    && pass "packages[0].transport.type is stdio" \
    || fail "packages[0].transport.type is '$TRANSPORT', expected stdio"

  # Registry validator rejects the old format outright.
  if jq -e '.packages[0] | has("registryBaseUrl") or has("version")' "$SERVER_JSON" >/dev/null; then
    fail "packages[0] carries registryBaseUrl/version — deprecated OCI format, hard-rejected by the registry validator. Use the tagged-identifier format (tag stamped by the workflow)."
  else
    pass "packages[0] has no registryBaseUrl/version (canonical OCI format)"
  fi

  # In-repo identifier must be tag-less; release.yml stamps ":$TAG" at publish.
  case "$IDENTIFIER" in
    *:*) fail "packages[0].identifier ($IDENTIFIER) carries a tag — repo copy must stay untagged (release.yml stamps the release tag at publish)" ;;
    ghcr.io/*) pass "packages[0].identifier ($IDENTIFIER) is untagged ghcr.io reference" ;;
    *) fail "packages[0].identifier ($IDENTIFIER) is not a ghcr.io reference" ;;
  esac

  # --- 3. Dockerfile ownership label -------------------------------------
  SERVER_NAME="$(jq -r '.name' "$SERVER_JSON")"
  LABEL_LINE="$(grep -o 'io.modelcontextprotocol.server.name="[^"]*"' "$REPO_ROOT/Dockerfile")"
  LABEL_NAME="$(printf '%s' "$LABEL_LINE" | cut -d'"' -f2)"
  if [ "$LABEL_NAME" = "$SERVER_NAME" ]; then
    pass "Dockerfile MCP name label matches server.json name ($SERVER_NAME)"
  else
    fail "Dockerfile io.modelcontextprotocol.server.name ('$LABEL_NAME') != server.json name ('$SERVER_NAME') — registry publish validates this pair"
  fi
else
  pass "no packages[] — remotes-only manifest, shape checks skipped"
fi

echo ""
if [ "$FAILURES" -gt 0 ]; then
  echo "test-server-json: $FAILURES failure(s)"
  exit 1
fi
echo "test-server-json: all checks passed"
